// Constants
var TAU = 6.283;           // ~2π
var PHI = 1.618;           // Golden ratio
var SQRT_HALF = 0.707;     // ~√0.5

// Physics configuration
var config = {
  attraction: 4000,        // Repulsion force between nodes
  frictionCoeff: 0.004,    // Spring stiffness fallback
  amplification: 0.92,     // Velocity damping factor
  dispersal: 0.0003,       // Centering/gravity force
  streamMax: 40,           // Max number of particles
  streamDecay: 0.04,       // Particle velocity decay rate
  theta: 0.06              // Camera smoothing factor
};

// Graph nodes (force-directed layout)
var nodes = [
  { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Spring connections between nodes
var edges = [
  { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera state
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particle stream
var particles = [];
var frameCount = 0;

// Find a node by ID
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// Physics simulation step
function simulate() {
  // 1. Node-to-node repulsion (Coulomb's law)
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = config.attraction / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2. Spring forces along edges (Hooke's law)
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNode(edges[e].a);
    var nodeB = findNode(edges[e].b);
    if (!nodeA || !nodeB) continue;

    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || config.frictionCoeff) * displacement;

    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3. Centering gravity + velocity damping + position update
  for (var n = 0; n < nodes.length; n++) {
    nodes[n].vx += (400 - nodes[n].x) * config.dispersal;
    nodes[n].vy += (300 - nodes[n].y) * config.dispersal;
    nodes[n].vx *= config.amplification;
    nodes[n].vy *= config.amplification;
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

// Spawn a new particle from a random node
function spawnParticle() {
  if (particles.length >= config.streamMax) return;

  var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT_HALF;

  particles.push({
    x: sourceNode.x,
    y: sourceNode.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * PHI * SQRT_HALF
  });
}

// Update all particles
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];
    p.vx *= (1 - config.streamDecay * 0.125);
    p.vy *= (1 - config.streamDecay * 0.125);
    p.x += p.vx;
    p.y += p.vy;
    p.age++;
    if (p.age > p.maxAge) particles.splice(i, 1);
  }
}

// Smooth camera interpolation
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.theta;
  camera.y += (cameraTarget.y - camera.y) * config.theta;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.theta;
}

// Main loop
function tick() {
  simulate();          // Physics step
  updateParticles();   // Move particles
  updateCamera();      // Smooth camera
  if (frameCount % 3 === 0) spawnParticle();  // Spawn particle every 3 frames
  frameCount++;
}

setInterval(tick, 16);  // ~60 FPS
```

## What It Does

This is a **force-directed graph simulation engine** — the backend logic (no rendering code shown) for an animated network visualization. Specifically:

1. **Force-Directed Graph Layout**: Six labeled nodes (`Hub`, `Alpha`, `Beta`, `Gamma`, `Delta`, `Epsilon`) connected by 8 edges are simulated using classical physics:
   - **Repulsion**: All nodes repel each other (inverse-square law, like electric charges) to prevent overlap
   - **Spring attraction**: Connected nodes are pulled together by Hooke's law springs with configurable rest lengths and stiffnesses
   - **Centering gravity**: A weak force pulls everything toward the center (400, 300)
   - **Velocity damping**: 8% velocity reduction per frame prevents oscillation

2. **Particle System**: Decorative particles spawn from random nodes every 3 frames (up to 40 max), drift outward with slowly decaying velocity, and die after 800–2000 frames. This creates a visual "streaming/emanating" effect.

3. **Smooth Camera**: A virtual camera smoothly interpolates toward a target position/zoom using linear interpolation (lerp) with factor 0.06.

4. **Runs at ~60 FPS** via `setInterval(..., 16)`.

The result would be a gently floating, self-organizing node graph with ambient particles — likely used as an **animated background, loading screen, or interactive data visualization**.
